static void DivSampleProducesTypedInstructions()
{
    var loweredModule = LowerSample("div");
    var function = loweredModule.Functions.Single(static function => function.Name == "div_i32");
    var startBlock = function.Blocks.Single(static block => block.Name == "start");
    var guardBlock = function.Blocks.Single(static block => block.Name == "bb1");
    var divideBlock = function.Blocks.Single(static block => block.Name == "bb2");
    var panicBlock = function.Blocks.Single(static block => block.Name == "panic");
    var overflowBlock = function.Blocks.Single(static block => block.Name == "panic1");

    Assert(startBlock.Instructions[0] is LoweredCompareInstruction zeroCheck
        && zeroCheck.Predicate == "eq"
        && zeroCheck.Type == "i32"
        && zeroCheck.Left == "b"
        && zeroCheck.Right == "0",
        "Expected div_i32 to begin with a typed divide-by-zero compare.");

    Assert(startBlock.Instructions[1] is LoweredConditionalBranchInstruction zeroBranch
        && zeroBranch.Condition == "_3"
        && zeroBranch.TrueTarget == "panic"
        && zeroBranch.FalseTarget == "bb1",
        "Expected div_i32 to branch to the panic block on zero divisors.");

    Assert(guardBlock.Instructions[2] is LoweredBinaryInstruction overflowGuard
        && overflowGuard.Operation == "and"
        && overflowGuard.Type == "i1"
        && overflowGuard.Left == "_4"
        && overflowGuard.Right == "_5",
        "Expected div_i32 to combine the overflow guard through a typed i1 and instruction.");

    Assert(divideBlock.Instructions[0] is LoweredBinaryInstruction divide
        && divide.Operation == "sdiv"
        && divide.Type == "i32"
        && divide.Left == "a"
        && divide.Right == "b",
        "Expected div_i32 to emit a typed signed division instruction in the happy path block.");

    Assert(panicBlock.Instructions[0] is LoweredCallInstruction zeroPanic
        && zeroPanic.Callee.Contains("panic_const_div_by_zero", StringComparison.Ordinal)
        && panicBlock.Instructions[1] is LoweredUnreachableInstruction,
        "Expected div_i32 to lower the divide-by-zero panic block to a typed call followed by unreachable.");

    Assert(overflowBlock.Instructions[0] is LoweredCallInstruction overflowPanic
        && overflowPanic.Callee.Contains("panic_const_div_overflow", StringComparison.Ordinal)
        && overflowBlock.Instructions[1] is LoweredUnreachableInstruction,
        "Expected div_i32 to lower the overflow panic block to a typed call followed by unreachable.");
}

