        Assert(block.Instructions[0] is LoweredLoadInstruction load
        && load.Type == "i32"
        && load.Source == "VALUES_I32[1]"
        && load.Result == "_0",
        "Expected read_second_i32 to contain a typed indexed global load instruction.");
    }

static void LocalArraySampleProducesTypedGetElementPointer()
{
    var loweredModule = LowerSample("local_array");
    var function = loweredModule.Functions.Single(static function => function.Name == "second_of_pair_i32");
    var block = function.Blocks.Single();

    Assert(block.Instructions[1] is LoweredGetElementPointerInstruction first
        && first.ElementType == "i32"
        && first.Base == "values"
        && first.Index == 0,
        "Expected second_of_pair_i32 to contain a typed first-element getelementptr instruction.");

    Assert(block.Instructions[3] is LoweredGetElementPointerInstruction second
        && second.ElementType == "i32"
        && second.Base == "values"
        && second.Index == 1,
        "Expected second_of_pair_i32 to contain a typed second-element getelementptr instruction.");
}

static void PairI64SampleProducesTypedPointerLoad()
{
    var loweredModule = LowerSample("pair_i64");
    var function = loweredModule.Functions.Single(static function => function.Name == "second_field_i64");
    var block = function.Blocks.Single();

    Assert(function.Parameters.Count == 1
        && function.Parameters[0].Type == "ptr"
        && function.Parameters[0].Name == "pair",
        "Expected second_field_i64 to lower to a single ptr pair parameter.");

    Assert(block.Instructions[0] is LoweredGetElementPointerInstruction gep
        && gep.ElementType == "i8"
        && gep.Base == "pair"
        && gep.Index == 8,
        "Expected second_field_i64 to compute the second field through a byte-offset getelementptr over the pair pointer.");

    Assert(block.Instructions[1] is LoweredLoadInstruction load
        && load.Type == "i64"
        && load.Source == "tmp.0"
        && load.Result == "_0",
        "Expected second_field_i64 to load an i64 from the computed pointer address.");
}

