static void AddSampleBuildsFromCargoManifest()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("add");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "add_i32");

    Assert(function.ReturnType == "i32", $"Expected Cargo-built add_i32 to lower to return type i32, but got '{function.ReturnType}'.");
    Assert(function.Parameters.Count == 2, $"Expected Cargo-built add_i32 to have 2 parameters, but got {function.Parameters.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(function.Parameters[0].Type == "i32" && function.Parameters[0].Name == "a", "Expected Cargo-built add_i32 parameter a to lower as i32 a.");
    Assert(function.Parameters[1].Type == "i32" && function.Parameters[1].Name == "b", "Expected Cargo-built add_i32 parameter b to lower as i32 b.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "add_i32", [3, 4], llvmRoot);
    Assert(Equals(actualResult, 7), $"Expected Cargo-built add_i32 invocation to return 7, but got '{actualResult}'.");
}

static void AddSampleBuildsWithBuildStdCore()
{
    if (!TryGetRustcSysroot("nightly", out var sysroot))
    {
        throw new SkipTestException("nightly Rust toolchain is not available.");
    }

    var rustSourcePath = Path.Combine(sysroot, "lib", "rustlib", "src", "rust", "library");
    if (!Directory.Exists(rustSourcePath))
    {
        throw new SkipTestException("nightly rust-src component is not installed.");
    }

    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcodeWithOptions(
        "add",
        new RustBitcodeBuildOptions
        {
            Toolchain = "nightly",
            BuildStd = "core"
        });

    var report = BitcodeArtifactInspector.Inspect(bitcodePath, llvmRoot);
    var moduleSummary = report.ModuleSummary ?? throw new InvalidOperationException("Expected a module summary for build-std core add.");
    Assert(moduleSummary.Functions.Count == 1, $"Expected build-std core add to contain one function, but found {moduleSummary.Functions.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(moduleSummary.Functions.Any(static function => function.Name == "add_i32"), "Expected build-std core add to contain add_i32.");

    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "add_i32");
    Assert(function.Blocks.Count == 1, $"Expected build-std core add_i32 to lower to one block, but got {function.Blocks.Count.ToString(CultureInfo.InvariantCulture)}.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "add_i32", [19, 23], llvmRoot);
    Assert(Equals(actualResult, 42), $"Expected build-std core add_i32 invocation to return 42, but got '{actualResult}'.");
}

static void AllocOnlyProbeBuildsWithBuildStdAlloc()
{
    if (!TryGetRustcSysroot("nightly", out var sysroot))
    {
        throw new SkipTestException("nightly Rust toolchain is not available.");
    }

    var rustSourcePath = Path.Combine(sysroot, "lib", "rustlib", "src", "rust", "library");
    if (!Directory.Exists(rustSourcePath))
    {
        throw new SkipTestException("nightly rust-src component is not installed.");
    }

    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcodeWithOptions(
        "alloc_only_probe",
        new RustBitcodeBuildOptions
        {
            Toolchain = "nightly",
            BuildStd = "core,alloc"
        });

    var report = BitcodeArtifactInspector.Inspect(bitcodePath, llvmRoot);
    var moduleSummary = report.ModuleSummary ?? throw new InvalidOperationException("Expected a module summary for build-std alloc probe.");
    Assert(moduleSummary.Functions.Any(static function => function.Name == "alloc_vec_capacity_score"), "Expected build-std alloc probe to contain alloc_vec_capacity_score.");
    Assert(moduleSummary.Functions.Any(static function => function.Name.Contains("rust_alloc", StringComparison.Ordinal)), "Expected build-std alloc probe to contain the Rust global allocator shim.");

    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "alloc_vec_capacity_score");
    Assert(function.Blocks.Count == 1, $"Expected build-std alloc probe to lower to one block, but got {function.Blocks.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(!string.Equals(function.Blocks[0].Name, "start", StringComparison.Ordinal) && !string.Equals(function.Blocks[0].Name, "entry", StringComparison.Ordinal), "Expected build-std alloc probe to pin an optimized non-canonical entry block label.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "alloc_vec_capacity_score", [], llvmRoot);
    Assert(Equals(actualResult, 4), $"Expected build-std alloc probe invocation to return 4, but got '{actualResult}'.");
}

static void StdFsBuildsWithBuildStdStd()
{
    if (!TryGetRustcSysroot("nightly", out var sysroot))
    {
        throw new SkipTestException("nightly Rust toolchain is not available.");
    }

    var rustSourcePath = Path.Combine(sysroot, "lib", "rustlib", "src", "rust", "library");
    if (!Directory.Exists(rustSourcePath))
    {
        throw new SkipTestException("nightly rust-src component is not installed.");
    }

    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcodeWithOptions(
        "std_fs",
        new RustBitcodeBuildOptions
        {
            Toolchain = "nightly",
            BuildStd = "std,panic_abort"
        });

    var report = BitcodeArtifactInspector.Inspect(bitcodePath, llvmRoot);
    var moduleSummary = report.ModuleSummary ?? throw new InvalidOperationException("Expected a module summary for build-std std_fs.");
    Assert(moduleSummary.Functions.Any(static function => function.Name == "std_fs_line_count"), "Expected build-std std_fs to contain std_fs_line_count.");
    Assert(moduleSummary.Globals.Count >= 3, $"Expected build-std std_fs to preserve path and panic globals, but found {moduleSummary.Globals.Count.ToString(CultureInfo.InvariantCulture)} globals.");

    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "std_fs_line_count");
    Assert(function.Blocks.Count >= 1, "Expected build-std std_fs_line_count to lower at least one block.");
    Assert(function.Blocks.Any(static block => block.Instructions.OfType<LoweredCallInstruction>().Any(static call => call.Callee.Contains("read_to_string", StringComparison.Ordinal))),
        "Expected build-std std_fs to preserve the std::fs read_to_string call on the success path.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "std_fs_line_count", [], llvmRoot);
    Assert(Equals(actualResult, 3), $"Expected build-std std_fs_line_count invocation to return 3, but got '{actualResult}'.");
}

static void BinTrivialSampleBuildsFromCargoManifest()
