static void AndSampleBuildsFromCargoManifest()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("and");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "and_i32");

    Assert(function.Blocks.Count == 1, $"Expected Cargo-built and_i32 to lower to a single block, but got {function.Blocks.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(function.Blocks[0].Instructions[0] is LoweredBinaryInstruction binary
        && binary.Operation == "and"
        && binary.Type == "i32"
        && binary.Left == "b"
        && binary.Right == "a",
        "Expected Cargo-built and_i32 to lower to a typed and instruction.");

    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "and_i32", [6, 3], llvmRoot);
    Assert(Equals(actualResult, 2), $"Expected Cargo-built and_i32 invocation to return 2, but got '{actualResult}'.");
}

