    var leftResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "select_i32", [0, 11, 22], llvmRoot);
    Assert(Equals(leftResult, 11), $"Expected Cargo-built select_i32 invocation with flag 0 to return 11, but got '{leftResult}'.");

    var rightResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "select_i32", [1, 11, 22], llvmRoot);
    Assert(Equals(rightResult, 22), $"Expected Cargo-built select_i32 invocation with flag 1 to return 22, but got '{rightResult}'.");
}

