{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("xor_fold_vectorized");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "xor_fold_i32");
    var vectorBlock = function.Blocks.Single(static block => block.Name == "vector.body");
    var middleBlock = function.Blocks.Single(static block => block.Name == "middle.block");

    Assert(function.Blocks.Any(static block => block.Name == "vector.body"), "Expected Cargo-built xor_fold_vectorized to include a vector.body block.");
    Assert(vectorBlock.Instructions.OfType<LoweredPhiInstruction>().Any(static phi =>
            phi.Type == "<4 x i32>"
            && phi.Incoming.Count == 2
            && phi.Incoming.Any(static incoming => incoming.Value == "zeroinitializer")),
        "Expected Cargo-built xor_fold_vectorized to preserve a zero-initialized vector phi in the vector body.");
    Assert(vectorBlock.Instructions.OfType<LoweredPhiInstruction>().Any(static phi =>
            phi.Type == "<4 x i32>"
            && phi.Incoming.Count == 2
            && phi.Incoming.Any(static incoming => incoming.Value == "<i32 0, i32 1, i32 2, i32 3>")),
        "Expected Cargo-built xor_fold_vectorized to preserve the induction vector literal phi in the vector body.");
    Assert(vectorBlock.Instructions.OfType<LoweredBinaryInstruction>().Any(static binary => binary.Type == "<4 x i32>" && binary.Operation == "add"),
        "Expected Cargo-built xor_fold_vectorized to preserve vector add operations in the vector body.");
    Assert(vectorBlock.Instructions.OfType<LoweredBinaryInstruction>().Any(static binary => binary.Type == "<4 x i32>" && binary.Operation == "xor"),
        "Expected Cargo-built xor_fold_vectorized to preserve vector xor operations in the vector body.");
    Assert(middleBlock.Instructions.OfType<LoweredCallInstruction>().Any(static call => call.Callee == "llvm.vector.reduce.xor.v4i32"),
        "Expected Cargo-built xor_fold_vectorized to preserve the vector xor reduction intrinsic.");

    var smallResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "xor_fold_i32", [5], llvmRoot);
    Assert(Equals(smallResult, 4), $"Expected Cargo-built xor_fold_vectorized invocation with n = 5 to return 4, but got '{smallResult}'.");

    var alignedResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "xor_fold_i32", [8], llvmRoot);
    Assert(Equals(alignedResult, 0), $"Expected Cargo-built xor_fold_vectorized invocation with n = 8 to return 0, but got '{alignedResult}'.");
}

