        "Expected Cargo-built min_xor_i64_vectorized to preserve lane-wise signed min intrinsics in the vector body.");
    Assert(middleBlock.Instructions.OfType<LoweredCallInstruction>().Any(static call => call.Callee == "llvm.vector.reduce.smin.v2i64"),
        "Expected Cargo-built min_xor_i64_vectorized to preserve the vector i64 signed min reduction intrinsic.");

