static void CallChainCargoSummaryClassifiesAlias()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("call_chain");
    var report = BitcodeArtifactInspector.Inspect(bitcodePath, llvmRoot);
    var moduleSummary = report.ModuleSummary ?? throw new InvalidOperationException("Expected a module summary for Cargo-built call_chain.");

    Assert(moduleSummary.Functions.Count == 1, $"Expected Cargo-built call_chain summary to contain one concrete function after optimization, but found {moduleSummary.Functions.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(moduleSummary.Functions.Any(static function => function.Name == "add_one_i32"), "Expected Cargo-built call_chain summary to contain add_one_i32 as the concrete function.");
    Assert(moduleSummary.Aliases.Count == 1, $"Expected Cargo-built call_chain summary to contain one alias, but found {moduleSummary.Aliases.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(moduleSummary.Aliases.Any(static alias => alias.Name == "call_chain_i32" && alias.Target == "add_one_i32"), "Expected Cargo-built call_chain summary to classify call_chain_i32 as an alias to add_one_i32.");
    Assert(moduleSummary.Globals.Count == 0, $"Expected Cargo-built call_chain summary to classify aliases separately from globals, but found {moduleSummary.Globals.Count.ToString(CultureInfo.InvariantCulture)} globals.");
}

static void PairRightSampleBuildsFromCargoManifest()
{
    var (bitcodePath, llvmRoot) = BuildCargoSampleBitcode("pair_right");
    var loweredModule = LoweredIrLowerer.LowerBitcode(bitcodePath, llvmRoot);
    var function = loweredModule.Functions.Single(static function => function.Name == "second_field_i32");

    Assert(function.Parameters.Count == 1, $"Expected Cargo-built second_field_i32 to lower to one packed parameter, but got {function.Parameters.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(function.Parameters[0].Type == "i64", $"Expected Cargo-built second_field_i32 to accept an i64 packed parameter, but got '{function.Parameters[0].Type}'.");
    Assert(function.Blocks.Count == 1, $"Expected Cargo-built second_field_i32 to lower to a single block, but got {function.Blocks.Count.ToString(CultureInfo.InvariantCulture)}.");
    Assert(function.Blocks[0].Instructions[0] is LoweredBinaryInstruction shift
        && shift.Operation == "lshr"
        && shift.Type == "i64"
        && shift.Right == "32",
        "Expected Cargo-built second_field_i32 to start with a logical right shift over the packed i64 argument.");
    Assert(function.Blocks[0].Instructions[1] is LoweredTruncateInstruction trunc
        && trunc.FromType == "i64"
        && trunc.ToType == "i32",
        "Expected Cargo-built second_field_i32 to truncate the shifted i64 value to i32.");

    long packedPair = ((long)(uint)9 << 32) | (uint)3;
    var actualResult = LoweredAssemblyInvoker.InvokeBitcode(bitcodePath, "second_field_i32", [packedPair], llvmRoot);
    Assert(Equals(actualResult, 9), $"Expected Cargo-built second_field_i32 invocation to return 9, but got '{actualResult}'.");
}

