static void AssertEmissionResult(string sampleName, string methodName, object?[] arguments, object expectedResult)
{
    var workspaceRoot = FindWorkspaceRoot();
    if (workspaceRoot is null)
    {
        throw new InvalidOperationException("Workspace root could not be determined.");
    }

    var sampleArtifactPath = Path.Combine(workspaceRoot, "artifacts", "out", sampleName, $"{sampleName}.bc");
    var llvmRoot = Path.Combine(workspaceRoot, "artifacts", "toolchains", "llvm", "clang+llvm-20.1.8-x86_64-windows");
    var llvmOptPath = Path.Combine(llvmRoot, "bin", "llvm-opt.exe");

    if (!File.Exists(sampleArtifactPath) || !File.Exists(llvmOptPath))
    {
        throw new SkipTestException($"Sample artifact or llvm-prebuilt distro is not available yet for '{sampleName}'.");
    }

    using var tempAssembly = TemporaryFile.CreateEmpty(".dll");
    LoweredAssemblyEmitter.EmitBitcode(sampleArtifactPath, tempAssembly.Path, llvmRoot);

    var loadContext = new AssemblyLoadContext($"rust-msil-{sampleName}-{Guid.NewGuid():N}", isCollectible: true);
    try
    {
        using var assemblyStream = new MemoryStream(File.ReadAllBytes(tempAssembly.Path));
        var assembly = loadContext.LoadFromStream(assemblyStream);
        var generatedType = assembly.GetType("RustMcil.GeneratedModule")
            ?? throw new InvalidOperationException("Emitted assembly did not contain RustMcil.GeneratedModule.");
        var method = generatedType.GetMethod(methodName, BindingFlags.Public | BindingFlags.Static)
            ?? throw new InvalidOperationException($"Emitted assembly did not contain method '{methodName}'.");

        var actualResult = method.Invoke(null, arguments);
        Assert(Equals(actualResult, expectedResult), $"Expected emitted method '{methodName}' to return '{expectedResult}', but got '{actualResult}'.");
    }
    finally
    {
        loadContext.Unload();
    }
}

static void AssertEmissionThrows<TException>(string sampleName, string methodName, object?[] arguments) where TException : Exception
{
    var workspaceRoot = FindWorkspaceRoot();
    if (workspaceRoot is null)
    {
        throw new InvalidOperationException("Workspace root could not be determined.");
    }

    var sampleArtifactPath = Path.Combine(workspaceRoot, "artifacts", "out", sampleName, $"{sampleName}.bc");
    var llvmRoot = Path.Combine(workspaceRoot, "artifacts", "toolchains", "llvm", "clang+llvm-20.1.8-x86_64-windows");
    var llvmOptPath = Path.Combine(llvmRoot, "bin", "llvm-opt.exe");

    if (!File.Exists(sampleArtifactPath) || !File.Exists(llvmOptPath))
    {
        throw new SkipTestException($"Sample artifact or llvm-prebuilt distro is not available yet for '{sampleName}'.");
    }

    using var tempAssembly = TemporaryFile.CreateEmpty(".dll");
    LoweredAssemblyEmitter.EmitBitcode(sampleArtifactPath, tempAssembly.Path, llvmRoot);

    var loadContext = new AssemblyLoadContext($"rust-msil-{sampleName}-throws-{Guid.NewGuid():N}", isCollectible: true);
    try
    {
        using var assemblyStream = new MemoryStream(File.ReadAllBytes(tempAssembly.Path));
        var assembly = loadContext.LoadFromStream(assemblyStream);
        var generatedType = assembly.GetType("RustMcil.GeneratedModule")
            ?? throw new InvalidOperationException("Emitted assembly did not contain RustMcil.GeneratedModule.");
        var method = generatedType.GetMethod(methodName, BindingFlags.Public | BindingFlags.Static)
            ?? throw new InvalidOperationException($"Emitted assembly did not contain method '{methodName}'.");

        try
        {
            method.Invoke(null, arguments);
        }
        catch (TargetInvocationException ex) when (ex.InnerException is TException)
        {
            return;
        }

        throw new InvalidOperationException($"Expected emitted method '{methodName}' to throw '{typeof(TException).Name}'.");
    }
    finally
    {
        loadContext.Unload();
    }
}

