static void AssertInvocationThrows<TException>(string sampleName, string methodName, IReadOnlyList<object?> arguments) where TException : Exception
{
    var workspaceRoot = FindWorkspaceRoot();
    if (workspaceRoot is null)
    {
        throw new InvalidOperationException("Workspace root could not be determined.");
    }

    var sampleArtifactPath = Path.Combine(workspaceRoot, "artifacts", "out", sampleName, $"{sampleName}.bc");
    var llvmRoot = Path.Combine(workspaceRoot, "artifacts", "toolchains", "llvm", "clang+llvm-20.1.8-x86_64-windows");
    var llvmOptPath = Path.Combine(llvmRoot, "bin", "llvm-opt.exe");

    if (!File.Exists(sampleArtifactPath) || !File.Exists(llvmOptPath))
    {
        throw new SkipTestException($"Sample artifact or llvm-prebuilt distro is not available yet for '{sampleName}'.");
    }

    try
    {
        LoweredAssemblyInvoker.InvokeBitcode(sampleArtifactPath, methodName, arguments, llvmRoot);
    }
    catch (TargetInvocationException ex) when (ex.InnerException is TException)
    {
        return;
    }
    catch (TException)
    {
        return;
    }

    throw new InvalidOperationException($"Expected invoked method '{methodName}' to throw '{typeof(TException).Name}'.");
}

static void AssertUnmanagedPairI64Result(Action<IntPtr> assertion)
{
    var pointer = Marshal.AllocHGlobal(16);
    try
    {
        Marshal.WriteInt64(pointer, 0, 3L);
        Marshal.WriteInt64(pointer, 8, 9L);
        assertion(pointer);
    }
    finally
    {
        Marshal.FreeHGlobal(pointer);
    }
}

void RunTest(string name, Action test, ICollection<string> failures)
{
    if (requestedTests is not null && !requestedTests.Contains(name))
    {
        return;
    }

    try
    {
        test();
        Console.WriteLine($"PASS {name}");
    }
    catch (Exception ex)
    {
        failures.Add($"{name}: {ex.Message}");
    }
}

void RunOptionalTest(string name, Action test, ICollection<string> failures)
{
    if (requestedTests is not null && !requestedTests.Contains(name))
    {
        return;
    }

    try
    {
        test();
        Console.WriteLine($"PASS {name}");
    }
    catch (SkipTestException ex)
    {
        Console.WriteLine($"SKIP {name}: {ex.Message}");
    }
    catch (Exception ex)
    {
        failures.Add($"{name}: {ex.Message}");
    }
}

static void ExpectException<TException>(Action action) where TException : Exception
{
    try
    {
        action();
    }
    catch (TargetInvocationException ex) when (ex.InnerException is TException)
    {
        return;
    }
    catch (TException)
    {
        return;
    }

    throw new InvalidOperationException($"Expected exception of type {typeof(TException).Name}.");
}

static void Assert(bool condition, string message)
{
    if (!condition)
    {
        throw new InvalidOperationException(message);
    }
}

static bool ContainsAdjacent(IReadOnlyList<string> values, string first, string second)
{
    for (var index = 0; index < values.Count - 1; index++)
    {
        if (string.Equals(values[index], first, StringComparison.Ordinal)
            && string.Equals(values[index + 1], second, StringComparison.Ordinal))
        {
            return true;
        }
    }

    return false;
}

static bool TryGetRustcSysroot(string toolchain, out string sysroot)
{
    var startInfo = new System.Diagnostics.ProcessStartInfo
    {
        FileName = "rustc",
        RedirectStandardOutput = true,
        RedirectStandardError = true,
        UseShellExecute = false,
        CreateNoWindow = true
    };
    startInfo.ArgumentList.Add($"+{toolchain}");
    startInfo.ArgumentList.Add("--print");
    startInfo.ArgumentList.Add("sysroot");

    try
    {
        using var process = System.Diagnostics.Process.Start(startInfo);
        if (process is null)
        {
            sysroot = string.Empty;
            return false;
        }

        var standardOutputTask = process.StandardOutput.ReadToEndAsync();
        var standardErrorTask = process.StandardError.ReadToEndAsync();
        process.WaitForExit();
        Task.WaitAll(standardOutputTask, standardErrorTask);

        sysroot = standardOutputTask.GetAwaiter().GetResult().Trim();
        return process.ExitCode == 0 && !string.IsNullOrWhiteSpace(sysroot);
    }
    catch
    {
        sysroot = string.Empty;
        return false;
    }
}

static string? FindWorkspaceRoot()
{
    var directory = new DirectoryInfo(Directory.GetCurrentDirectory());
    while (directory is not null)
    {
        if (Directory.Exists(Path.Combine(directory.FullName, ".git"))
            || File.Exists(Path.Combine(directory.FullName, "README.md")))
        {
            return directory.FullName;
        }

        directory = directory.Parent;
    }

    return null;
}

static void RustBitcodeBuildStdRequiresToolchain()
{
    var options = new RustBitcodeBuildOptions { BuildStd = "core" };
    ExpectException<InvalidOperationException>(() => RustBitcodeCompiler.CreateCargoRustcArguments("Cargo.toml", options));
}

static void RustBitcodeBuildStdFeaturesRequireBuildStd()
{
    var options = new RustBitcodeBuildOptions
    {
        Toolchain = "nightly",
        BuildStdFeatures = "panic_immediate_abort"
    };

    ExpectException<InvalidOperationException>(() => RustBitcodeCompiler.CreateCargoRustcArguments("Cargo.toml", options));
}

static void RustBitcodeBuildArgumentsIncludeBuildStdFeatures()
{
    var options = new RustBitcodeBuildOptions
    {
        Toolchain = "nightly",
        BuildStd = "core,alloc",
        BuildStdFeatures = "panic_immediate_abort",
        Target = "x86_64-pc-windows-msvc"
    };

    var arguments = RustBitcodeCompiler.CreateCargoRustcArguments("Cargo.toml", options).ToArray();
    Assert(arguments.Contains("+nightly"), "Expected cargo arguments to include the configured toolchain.");
    Assert(ContainsAdjacent(arguments, "-Z", "build-std=core,alloc"), "Expected cargo arguments to include build-std components.");
    Assert(ContainsAdjacent(arguments, "-Z", "build-std-features=panic_immediate_abort"), "Expected cargo arguments to include build-std features.");
    Assert(ContainsAdjacent(arguments, "--target", "x86_64-pc-windows-msvc"), "Expected cargo arguments to include the configured target.");
}

static void RuntimeSplitFacadeForwardsNumericHelpers()
{
    Assert(RustMcil.Runtime.NumericRuntime.RemEuclidI32(-5, 3) == 1, "Expected Runtime numeric rem_euclid i32 helper to match Rust semantics.");
    Assert(RuntimeBridgeHelpers.RemEuclidI32(-5, 3) == RustMcil.Runtime.NumericRuntime.RemEuclidI32(-5, 3), "Expected Backend runtime facade to forward i32 rem_euclid.");
    Assert(RustMcil.Runtime.NumericRuntime.RemEuclidI64(-17, 5) == 3, "Expected Runtime numeric rem_euclid i64 helper to match Rust semantics.");
    Assert(RuntimeBridgeHelpers.RemEuclidI64(-17, 5) == RustMcil.Runtime.NumericRuntime.RemEuclidI64(-17, 5), "Expected Backend runtime facade to forward i64 rem_euclid.");
    ExpectException<DivideByZeroException>(() => RustMcil.Runtime.NumericRuntime.RemEuclidI32(1, 0));
}

static void RuntimeSplitFacadeForwardsOsHelpers()
{
    var expectedArgumentCount = Environment.GetCommandLineArgs().Length;
    Assert(RustMcil.Os.HostEnvironment.CommandLineArgCount() == expectedArgumentCount, "Expected OS host environment helper to expose the process argument count.");
    Assert(RuntimeBridgeHelpers.CommandLineArgCount() == RustMcil.Os.HostEnvironment.CommandLineArgCount(), "Expected Backend runtime facade to forward command-line argument count.");
}

static void RustBitcodeBuildStdArgumentsAvoidFakeLinker()
{
    var options = new RustBitcodeBuildOptions
    {
        Toolchain = "nightly",
        BuildStd = "std,panic_abort",
        Target = "x86_64-pc-windows-msvc"
    };

    var arguments = RustBitcodeCompiler.CreateCargoRustcArguments("Cargo.toml", options).ToArray();
    Assert(ContainsAdjacent(arguments, "-Z", "build-std=std,panic_abort"), "Expected cargo arguments to request the std build-std rung.");
    Assert(ContainsAdjacent(arguments, "--emit", "llvm-bc"), "Expected cargo arguments to request LLVM bitcode directly.");
    Assert(arguments.All(static argument => !argument.Contains("rsfakelink", StringComparison.OrdinalIgnoreCase)), "Expected build-std cargo arguments to avoid the historical rsfakelink path.");
    Assert(arguments.All(static argument => !argument.Contains("linker", StringComparison.OrdinalIgnoreCase)), "Expected build-std cargo arguments to avoid linker replacement until a fixture proves it is needed.");
}

file sealed class SkipTestException(string message) : Exception(message);

file sealed class TemporaryFile : IDisposable
{
    private TemporaryFile(string path)
    {
        Path = path;
    }

    public string Path { get; }

    public static TemporaryFile Create(ReadOnlySpan<byte> content)
    {
        var path = System.IO.Path.Combine(System.IO.Path.GetTempPath(), $"rust-msil-test-{Guid.NewGuid():N}.bin");
        File.WriteAllBytes(path, content.ToArray());
        return new TemporaryFile(path);
    }

    public static TemporaryFile CreateEmpty(string extension)
    {
        var path = System.IO.Path.Combine(System.IO.Path.GetTempPath(), $"rust-msil-test-{Guid.NewGuid():N}{extension}");
        return new TemporaryFile(path);
    }

    public void Dispose()
    {
        if (File.Exists(Path))
        {
            File.Delete(Path);
        }

        var runtimeConfigPath = System.IO.Path.ChangeExtension(Path, ".runtimeconfig.json");
        if (File.Exists(runtimeConfigPath))
        {
            File.Delete(runtimeConfigPath);
        }
    }
}